pr_description:
Allow custom rules in plugins.  Full support, tests, docs for custom plugins. 

Here's a big fat example of a plugin using all the new powers to create **3 custom rules**.

```js

  // Register this plugin
  context.addPlugin({
    name: 'Example Plugin',
    description: 'I help test plugins',
    snapshot: async context => {
      context.addedSnapshot = true
    },
    rules: {
      checkThing: {
        check: async (rule, context) => {
          return {
            pass: true,
            message: 'Yeah good check!',
          }
        },
        snapshot: async (rule, context) => [
          {
            prop: 'semver',
            value: '12.0.0',
          },
        ],
        report: async (rule, context, report) => {
          report.addCLI({
            binary: 'node',
            version: '10',
            desired: '12',
          })
        },
      },
      checkSecondThing: {
        check: async (rule, context) => {
          return {
            pass: false,
            message: 'Boooo failed check',
          }
        },
        snapshot: async (rule, context) => [
          {
            prop: 'semver',
            value: '12.0.0',
          },
          {
            prop: 'nachos',
            value: true,
          },
        ],
      },
      checkThirdThing: {
        check: async (rule, context) => {
          return {
            pass: true,
            message: 'PAZZZZZ',
          }
        },
        snapshot: async (rule, context) => [],
        report: async (rule, context, report) => {
          report.customRules.push({
            title: 'Nachos',
            table: [
              ['Title 1', 'Title 2', 'Title 3'],
              ['Some Val 1', 'Some Val 2', 'Some Val 3'],
              ['Dat Val 1', 'Dat Val 2', 'Dat Val 3'],
            ],
          })
        },
      },
    },
  })

```

Closes #107

